"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[72568],{49795(e,t,o){o.r(t),o.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>f,frontMatter:()=>s,metadata:()=>n,toc:()=>l});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 Revenue from Contracts with Customers/compensation-for-delays-or-cancellat-140b02cec9","title":"Compensation for Delays or Cancellations (IFRS 15)","description":"September 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 Revenue from Contracts with Customers/Compensation for Delays or Cancellations (IFRS 15).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 Revenue from Contracts with Customers","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/compensation-for-delays-or-cancellat-140b02cec9","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/compensation-for-delays-or-cancellat-140b02cec9","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"id":"compensation-for-delays-or-cancellat-140b02cec9","title":"Compensation for Delays or Cancellations (IFRS 15)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/compensation-for-delays-or-cancellat-140b02cec9","sidebar_position":2},"sidebar":"knowledgeSidebar","previous":{"title":"Assessment of promised goods or services (IFRS 15)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/assessment-of-promised-goods-or-serv-0eae0a67ed"},"next":{"title":"Costs to Fulfil a Contract (IFRS 15)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/costs-to-fulfil-a-contract-ifrs-15-6af726fae2"}}');var i=o(74848),a=o(28453);let s={id:"compensation-for-delays-or-cancellat-140b02cec9",title:"Compensation for Delays or Cancellations (IFRS 15)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/compensation-for-delays-or-cancellat-140b02cec9",sidebar_position:2},r="Compensation for Delays or Cancellations (IFRS 15)",c={},l=[];function d(e){let t={h1:"h1",header:"header",p:"p",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"compensation-for-delays-or-cancellations-ifrs-15",children:"Compensation for Delays or Cancellations (IFRS 15)"})}),"\n",(0,i.jsx)(t.p,{children:"September 2019"}),"\n",(0,i.jsx)(t.p,{children:"The Committee received a request about an airline\u2019s obligation to compensate customers for delayed or cancelled flights. In the fact pattern described in the request:"}),"\n",(0,i.jsx)(t.p,{children:"a. legislation gives a flight passenger (customer) the right to be compensated by the flight provider (entity) for delays and cancellations subject to specified conditions in the legislation. The legislation stipulates the amount of compensation, which is unrelated to the amount the customer pays for a flight.\nb. the legislation creates enforceable rights and obligations, and forms part of the terms of a contract between the entity and a customer.\nc. applying IFRS 15 to a contract with a customer, the entity identifies as a performance obligation its promise to transfer a flight service to the customer."}),"\n",(0,i.jsx)(t.p,{children:"The request asked whether the entity accounts for its obligation to compensate customers either: (a) as variable consideration applying paragraphs 50\u201359 of IFRS 15; or (b) applying IAS 37 Provisions, Contingent Liabilities and Contingent Assets, separately from its performance obligation to transfer a flight service to the customer."}),"\n",(0,i.jsx)(t.p,{children:"Paragraph 47 of IFRS 15 requires an entity to \u2018consider the terms of the contract and its customary business practices in determining the transaction price. The transaction price is the amount of consideration to which an entity expects to be entitled in exchange for transferring promised goods or services to a customer\u2026The consideration promised in a contract with a customer may include fixed amounts, variable amounts, or both\u2019. Paragraph 51 of IFRS 15 lists examples of common types of variable consideration\u2014\u2018discounts, rebates, refunds, credits, price concessions, incentives, performance bonuses, penalties or other similar items\u2019."}),"\n",(0,i.jsx)(t.p,{children:"Paragraph B33 of IFRS 15 specifies requirements for an entity\u2019s obligation to pay compensation to a customer if its products cause harm or damage. An entity accounts for such an obligation applying IAS 37, separately from its performance obligation in the contract with the customer."}),"\n",(0,i.jsx)(t.p,{children:"The Committee observed that, in the fact pattern described in the request, the entity promises to transport the customer from one specified location to another within a specified time period after the scheduled flight time. If the entity fails to do so, the customer is entitled to compensation. Accordingly, any compensation for delays or cancellations forms part of the consideration to which the entity expects to be entitled in exchange for transferring the promised service to the customer; it does not represent compensation for harm or damage caused by the entity\u2019s products as described in paragraph B33. The fact that legislation, rather than the contract, stipulates the compensation payable does not affect the entity\u2019s determination of the transaction price \u2014the compensation gives rise to variable consideration in the same way that penalties for delayed transfer of an asset give rise to variable consideration as illustrated in Example 20 of the Illustrative Examples accompanying IFRS 15."}),"\n",(0,i.jsx)(t.p,{children:"Consequently, the Committee concluded that compensation for delays or cancellations, as described in the request, is variable consideration in the contract. Accordingly, the entity applies the requirements in paragraphs 50\u201359 of IFRS 15 in accounting for its obligation to compensate customers for delays or cancellations. The Committee did not consider the question of whether the amount of compensation recognised as a reduction of revenue is limited to reducing the transaction price to nil."}),"\n",(0,i.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS 15 provide an adequate basis for an entity to determine its accounting for obligations to compensate customers for delays or cancellations. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function f(e={}){let{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},28453(e,t,o){o.d(t,{R:()=>s,x:()=>r});var n=o(96540);let i={},a=n.createContext(i);function s(e){let t=n.useContext(a);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),n.createElement(a.Provider,{value:t},e.children)}}}]);